import classes from "./Avatar.module.css";

const Avatar = (props) => {
  return (
    <div className={classes["avatar-wrapper"]}>
      <img
        style={{ width: `${props.size}px`, height: `${props.size}px` }}
        className={`${classes["avatar-image"]}`}
        src={props.image}
        alt=" "
      ></img>
    </div>
  );
};

export default Avatar;
